import React, { useState } from "react";
import axios from "axios";

function MusicApp({ user }) {
  const [songs, setSongs] = useState([]);
  const [favorites, setFavorites] = useState([]);

  const BASE_URL = "http://127.0.0.1:5000";

  const fetchSongs = async (mood) => {
    const res = await axios.get(`${BASE_URL}/songs/${mood}`);
    setSongs(res.data);
  };

  const toggleFavorite = (title) => {
    setFavorites((prev) =>
      prev.includes(title)
        ? prev.filter((s) => s !== title)
        : [...prev, title]
    );
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h1>Welcome {user} 🎧</h1>

      <h2>Mood Music App</h2>

      <button onClick={() => fetchSongs("happy")}>Happy</button>
      <button onClick={() => fetchSongs("sad")}>Sad</button>

      <h3>Songs</h3>

      {songs.map((song, i) => (
        <div key={i}>
          <p>{song.title}</p>

          <button onClick={() => toggleFavorite(song.title)}>
            ❤️
          </button>
        </div>
      ))}

      <h3>Favorites</h3>
      {favorites.map((f, i) => (
        <p key={i}>⭐ {f}</p>
      ))}
    </div>
  );
}

export default MusicApp;
